```typescript
// config/loader.ts
class ConfigLoader {
  static loadConfig(env: string): PlatformConfig {
    // 1. Load base config
    const base = yaml.load(`config/base.yaml`);

    // 2. Load environment-specific overrides
    const envConfig = yaml.load(`config/${env}.yaml`) || {};

    // 3. Load secrets from .env
    dotenv.config();

    // 4. Interpolate ${VAR} placeholders
    const config = this.interpolate({
      ...base,
      ...envConfig
    });

    // 5. Validate against schema
    this.validate(config);

    return config;
  }

  private static interpolate(obj: any): any {
    // Replace ${VAR} with env.VAR, failing safely if missing
    return JSON.parse(
      JSON.stringify(obj).replace(
        /\$\{(\w+?)(?::(.+?))?\}/g,
        (_, key, defaultVal) => process.env[key] ?? defaultVal ?? 
          (() => { throw new Error(`Missing: ${key}`); })()
      )
    );
  }
}
