### Adapter Pattern for Integrations

```typescript
// adapters/embedder.ts
interface EmbedderFactory {
  create(config: EmbedderConfig): EmbedderService;
}

export class EmbedderAdapterRegistry {
  private adapters: Map<string, EmbedderFactory> = new Map([
    ["mock", new MockEmbedderFactory()],
    ["openai", new OpenAIEmbedderFactory()],
    ["ollama", new OllamaEmbedderFactory()],
  ]);

  static getAdapter(type: string): EmbedderService {
    if (process.env.NODE_ENV === "test") {
      return new MockEmbedder();
    }
    const factory = this.adapters.get(type);
    if (!factory) throw new Error(`Unknown embedder: ${type}`);
    return factory.create(config);
  }
}

