### Metrics Collection Points

```typescript
// Instrumentation in core flows
class InstrumentedRetriever {
  async retrieve(query: string, context: RetrievalContext) {
    const start = performance.now();
    const timer = setupTimer();

    try {
      const results = await this.vectorStore.query(...);

      metrics.record("retrieval.duration", performance.now() - start);
      metrics.record("retrieval.chunk_count", results.length);
      metrics.record("retrieval.top_similarity", results[0]?.score);

      logger.query(query, results, performance.now() - start);

      return results;
    } catch (error) {
      metrics.increment("retrieval.error");
      logger.error("Retrieval failed", { query, error });
      throw error;
    }
  }
}
