### Session Management

```typescript
// Thread-safe browser session pooling via MCP
class BrowserSessionPool {
  private pool: MCPBrowserToolset[] = [];
  private leases: Map<string, BrowserLease> = new Map();

  async acquire(config: SessionConfig): Promise<string> {
    // Lease a browser session (handle reuse, cleanup)
    const leaseId = generateId();
    this.leases.set(leaseId, { 
      server: await this.pool.pop() || await this.createNew(),
      acquiredAt: Date.now(),
      config 
    });
    return leaseId;
  }

  async release(leaseId: string) {
    const lease = this.leases.get(leaseId);
    await lease?.server.reset();
    this.pool.push(lease!.server);
    this.leases.delete(leaseId);
  }
}
